router.put("/api/logout", (req: Request, res: Response) => {
  const clearOptions = buildClearCookieOptions();

  const authCookieNames = [AUTH_COOKIE_NAME];
  const challengeCookieNames = [CHALLENGE_COOKIE_NAME];

  authCookieNames.forEach((cookieName) =>
    res.clearCookie(cookieName, clearOptions),
  );
  challengeCookieNames.forEach((cookieName) =>
    res.clearCookie(cookieName, clearOptions),
  );

  return res.status(204).send();
});

